// 1. Get the Check Status Node
const statusNode = $('HTTP Request5').first();

if (!statusNode) {
  throw new Error("âŒ I cannot find 'HTTP Request5'. Please re-run the previous nodes to fill the pipe.");
}

// 2. THE FIX: We look inside '.data' first
// The error log showed us that 'resultJson' is nested inside 'data'
const actualData = statusNode.json.data || statusNode.json;

// 3. Unzip the folder
let cleanUrl;
try {
  const dataObj = JSON.parse(actualData.resultJson);
  cleanUrl = dataObj.resultUrls[0];
} catch (error) {
  throw new Error("âŒ Parsing failed. Structure found: " + JSON.stringify(actualData));
}

// 4. Return the clean Link
return [
  {
    json: {
      clean_image_url: cleanUrl,
      prompt: $input.item.json.output
    }
  }
];
